// FetchResult holds the raw bytes, optional MIME type, and source URI.
type FetchResult struct {
	Data         []byte
	DetectedMime *string
	SourcePath   string
}

// S3Transport fetches documents from Amazon S3 (s3:// and s3a:// URIs).
type S3Transport struct{}

// CanHandle reports whether this transport handles the given URI.
func (t *S3Transport) CanHandle(uri string) bool {
	return strings.HasPrefix(uri, "s3://") || strings.HasPrefix(uri, "s3a://")
}

// S3FetchOptions carries optional parameters for Fetch.
type S3FetchOptions struct {
	Profile     string
	Region      string
	EndpointURL string
}

// Fetch retrieves an S3 object identified by uri.
func (t *S3Transport) Fetch(uri string, opts S3FetchOptions) (*FetchResult, error) {
	parsed, err := url.Parse(uri)
	if err != nil {
		return nil, fmt.Errorf("S3Transport.Fetch: parse URI: %w", err)
	}
	bucket := parsed.Hostname()
	key := strings.TrimPrefix(parsed.Path, "/")

	sessionOpts := session.Options{}
	if opts.Profile != "" {
		sessionOpts.Profile = opts.Profile
	}

	region := opts.Region
	if region == "" {
		region = os.Getenv("AWS_REGION")
	}
	if region == "" {
		region = os.Getenv("AWS_DEFAULT_REGION")
	}
	if region != "" {
		sessionOpts.Config.Region = aws.String(region)
	}

	sess, err := session.NewSessionWithOptions(sessionOpts)
	if err != nil {
		return nil, fmt.Errorf("S3Transport.Fetch: create session: %w", err)
	}

	s3Cfg := &aws.Config{}
	endpoint := opts.EndpointURL
	if endpoint == "" {
		endpoint = os.Getenv("AWS_ENDPOINT_OVERRIDE")
	}
	if endpoint != "" {
		s3Cfg.Endpoint = aws.String(endpoint)
	}

	svc := s3.New(sess, s3Cfg)
	output, err := svc.GetObject(&s3.GetObjectInput{
		Bucket: aws.String(bucket),
		Key:    aws.String(key),
	})
	if err != nil {
		return nil, fmt.Errorf("S3Transport.Fetch: get object s3://%s/%s: %w", bucket, key, err)
	}
	defer output.Body.Close()

	data, err := io.ReadAll(output.Body)
	if err != nil {
		return nil, fmt.Errorf("S3Transport.Fetch: read body: %w", err)
	}

	var detectedMime *string
	if output.ContentType != nil {
		detectedMime = output.ContentType
	}
	return &FetchResult{
		Data:         data,
		DetectedMime: detectedMime,
		SourcePath:   uri,
	}, nil
}

