// SftpTransport fetches documents via SFTP.
type SftpTransport struct{}

// CanHandle reports whether this transport handles sftp:// URIs.
func (t *SftpTransport) CanHandle(uri string) bool {
	return strings.HasPrefix(uri, "sftp://")
}

// SftpFetchOptions carries optional SFTP connection parameters.
type SftpFetchOptions struct {
	Port     int
	Username string
	Password string
	KeyPath  string
}

// Fetch downloads the remote file at uri over SFTP.
func (t *SftpTransport) Fetch(uri string, opts SftpFetchOptions) (*FetchResult, error) {
	parsed, err := url.Parse(uri)
	if err != nil {
		return nil, fmt.Errorf("SftpTransport.Fetch: parse URI: %w", err)
	}

	host := parsed.Hostname()
	port := opts.Port
	if port == 0 {
		if p := parsed.Port(); p != "" {
			port, err = strconv.Atoi(p)
			if err != nil {
				return nil, fmt.Errorf("SftpTransport.Fetch: invalid port %q: %w", p, err)
			}
		}
	}
	if port == 0 {
		port = 22
	}
	remotePath := parsed.Path

	username := opts.Username
	if username == "" && parsed.User != nil {
		username = parsed.User.Username()
	}
	password := opts.Password
	if password == "" && parsed.User != nil {
		password, _ = parsed.User.Password()
	}

	var authMethods []ssh.AuthMethod
	if opts.KeyPath != "" {
		key, readErr := os.ReadFile(opts.KeyPath)
		if readErr != nil {
			return nil, fmt.Errorf("SftpTransport.Fetch: read key file: %w", readErr)
		}
		signer, parseErr := ssh.ParsePrivateKey(key)
		if parseErr != nil {
			return nil, fmt.Errorf("SftpTransport.Fetch: parse private key: %w", parseErr)
		}
		authMethods = append(authMethods, ssh.PublicKeys(signer))
	}
	if password != "" {
		authMethods = append(authMethods, ssh.Password(password))
	}

	cfg := &ssh.ClientConfig{
		User:            username,
		Auth:            authMethods,
		HostKeyCallback: ssh.InsecureIgnoreHostKey(),
	}

	addr := fmt.Sprintf("%s:%d", host, port)
	sshClient, err := ssh.Dial("tcp", addr, cfg)
	if err != nil {
		return nil, fmt.Errorf("SftpTransport.Fetch: ssh dial %s: %w", addr, err)
	}
	defer sshClient.Close()

	sftpClient, err := sftp.NewClient(sshClient)
	if err != nil {
		return nil, fmt.Errorf("SftpTransport.Fetch: open sftp: %w", err)
	}
	defer sftpClient.Close()

	f, err := sftpClient.Open(remotePath)
	if err != nil {
		return nil, fmt.Errorf("SftpTransport.Fetch: open remote %s: %w", remotePath, err)
	}
	defer f.Close()

	data, err := io.ReadAll(f)
	if err != nil {
		return nil, fmt.Errorf("SftpTransport.Fetch: read remote %s: %w", remotePath, err)
	}

	return &FetchResult{
		Data:         data,
		DetectedMime: nil,
		SourcePath:   uri,
	}, nil
}

// FetchMessages retrieves messages matching the IMAP URI and returns them as FetchResult slice.
// limit, if > 0, caps the number of messages returned (most-recent first).
func (t *ImapTransport) FetchMessages(uri string, limit int) ([]*FetchResult, error) {
	parsed, err := url.Parse(uri)
	if err != nil {
		return nil, fmt.Errorf("ImapTransport.FetchMessages: parse URI: %w", err)
	}

	useSSL := parsed.Scheme == "imaps"
	host := parsed.Hostname()
	if host == "" {
		host = "localhost"
	}
	portStr := parsed.Port()
	port := 0
	if portStr != "" {
		port, err = strconv.Atoi(portStr)
		if err != nil {
			return nil, fmt.Errorf("ImapTransport.FetchMessages: invalid port: %w", err)
		}
	}
	if port == 0 {
		if useSSL {
			port = 993
		} else {
			port = 143
		}
	}

	var user, password string
	if parsed.User != nil {
		user, _ = url.QueryUnescape(parsed.User.Username())
		rawPass, _ := parsed.User.Password()
		password, _ = url.QueryUnescape(rawPass)
	}

	mailbox, _ := url.QueryUnescape(strings.TrimPrefix(parsed.Path, "/"))
	if mailbox == "" {
		mailbox = "INBOX"
	}

	qs := parsed.Query()
	searchCriteria := qs.Get("search")
	if searchCriteria == "" {
		searchCriteria = "ALL"
	}
	effectiveLimit := limit
	if effectiveLimit == 0 {
		if lStr := qs.Get("limit"); lStr != "" {
			effectiveLimit, err = strconv.Atoi(lStr)
			if err != nil {
				return nil, fmt.Errorf("ImapTransport.FetchMessages: invalid limit: %w", err)
			}
		}
	}

	addr := fmt.Sprintf("%s:%d", host, port)
	var c *client.Client
	if useSSL {
		c, err = client.DialTLS(addr, nil)
	} else {
		c, err = client.Dial(addr)
	}
	if err != nil {
		return nil, fmt.Errorf("ImapTransport.FetchMessages: dial %s: %w", addr, err)
	}
	defer func() {
		_ = c.Logout()
	}()

	if err = c.Login(user, password); err != nil {
		return nil, fmt.Errorf("ImapTransport.FetchMessages: login: %w", err)
	}

	if _, err = c.Select(mailbox, true); err != nil {
		return nil, fmt.Errorf("ImapTransport.FetchMessages: select %s: %w", mailbox, err)
	}

	criteria := imap.NewSearchCriteria()
	criteria.Text = []string{searchCriteria}
	uids, err := c.Search(criteria)
	if err != nil {
		return nil, fmt.Errorf("ImapTransport.FetchMessages: search: %w", err)
	}
	if len(uids) == 0 {
		return nil, nil
	}

	// Reverse for most-recent first.
	for i, j := 0, len(uids)-1; i < j; i, j = i+1, j-1 {
		uids[i], uids[j] = uids[j], uids[i]
	}
	if effectiveLimit > 0 && len(uids) > effectiveLimit {
		uids = uids[:effectiveLimit]
	}

	seqSet := new(imap.SeqSet)
	for _, uid := range uids {
		seqSet.AddNum(uid)
	}

	var results []*FetchResult
	messages := make(chan *imap.Message, 10)
	fetchErr := make(chan error, 1)
	go func() {
		fetchErr <- c.Fetch(seqSet, []imap.FetchItem{imap.FetchRFC822}, messages)
	}()

	for msg := range messages {
		if msg == nil {
			continue
		}
		r := msg.GetBody(&imap.BodySectionName{})
		if r == nil {
			continue
		}
		raw, readErr := io.ReadAll(r)
		if readErr != nil {
			log.Printf("ImapTransport: skipping message %d: %v", msg.SeqNum, readErr)
			continue
		}
		mimeType := "message/rfc822"
		source := fmt.Sprintf("imap://%s/%s/%d", host, mailbox, msg.SeqNum)
		results = append(results, &FetchResult{
			Data:         raw,
			DetectedMime: &mimeType,
			SourcePath:   source,
		})
	}

	if err = <-fetchErr; err != nil {
		return nil, fmt.Errorf("ImapTransport.FetchMessages: fetch RFC822: %w", err)
	}
	return results, nil
}

