// ImapTransport fetches email messages from an IMAP mailbox.
type ImapTransport struct{}

// CanHandle reports whether this transport handles imap:// or imaps:// URIs.
func (t *ImapTransport) CanHandle(uri string) bool {
	return strings.HasPrefix(uri, "imap://") || strings.HasPrefix(uri, "imaps://")
}

// Fetch returns the single most-recent message matching the URI.
func (t *ImapTransport) Fetch(uri string) (*FetchResult, error) {
	results, err := t.FetchMessages(uri, 1)
	if err != nil {
		return nil, fmt.Errorf("ImapTransport.Fetch: %w", err)
	}
	if len(results) == 0 {
		return nil, fmt.Errorf("ImapTransport.Fetch: no messages found for URI: %s", uri)
	}
	return results[0], nil
}

// Crawl queries all configured containers, caches items, and emits schema chunks.
// Returns the list of cosmos://{database}/{container}/{id} URIs plus one schema URI per container.
func (c *CosmosCrawler) Crawl(uri string) ([]string, error) {
	client, err := azcosmos.NewClientFromConnectionString(c.url+";"+c.key, nil)
	if err != nil {
		return nil, fmt.Errorf("CosmosCrawler.Crawl: create client: %w", err)
	}

	var containerNames []string
	if len(c.containers) > 0 {
		containerNames = c.containers
	} else {
		dbClient, dbErr := client.NewDatabase(c.database)
		if dbErr != nil {
			return nil, fmt.Errorf("CosmosCrawler.Crawl: get database client: %w", dbErr)
		}
		pager := dbClient.NewQueryContainersPager(nil)
		ctx := context.Background()
		for pager.More() {
			page, pageErr := pager.NextPage(ctx)
			if pageErr != nil {
				return nil, fmt.Errorf("CosmosCrawler.Crawl: list containers: %w", pageErr)
			}
			for _, props := range page.Containers {
				containerNames = append(containerNames, props.ID)
			}
		}
	}

	c.cache = make(map[string]*FetchResult)
	c.knownFields = make(map[string]struct{})
	c.knownContainers = append(c.knownContainers[:0], containerNames...)
	total := 0
	ctx := context.Background()

	for _, cname := range containerNames {
		containerClient, cErr := client.NewContainer(c.database, cname)
		if cErr != nil {
			return nil, fmt.Errorf("CosmosCrawler.Crawl: get container %s: %w", cname, cErr)
		}
		queryPager := containerClient.NewQueryItemsPager(
			c.query,
			azcosmos.PartitionKey{},
			&azcosmos.QueryOptions{PageSizeHint: int32(c.maxItemCount)},
		)

		var sample []map[string]interface{}
		cnameTotal := 0

		for queryPager.More() {
			page, pageErr := queryPager.NextPage(ctx)
			if pageErr != nil {
				return nil, fmt.Errorf("CosmosCrawler.Crawl: query %s: %w", cname, pageErr)
			}
			for _, rawItem := range page.Items {
				var item map[string]interface{}
				if unmarshalErr := json.Unmarshal(rawItem, &item); unmarshalErr != nil {
					return nil, fmt.Errorf("CosmosCrawler.Crawl: unmarshal item: %w", unmarshalErr)
				}
				itemID := fmt.Sprintf("%v", item["id"])
				if itemID == "<nil>" {
					itemID = strconv.Itoa(total)
				}
				if len(sample) < c.schemaSampleSize {
					sample = append(sample, item)
				}
				docURI := fmt.Sprintf("%s://%s/%s/%s", cosmosScheme, c.database, cname, itemID)
				payload := map[string]interface{}{
					"_source_meta": map[string]interface{}{
						"type":      "cosmos",
						"url":       c.url,
						"database":  c.database,
						"container": cname,
						"item_id":   itemID,
					},
				}
				for k, v := range item {
					payload[k] = v
				}
				encoded, encErr := json.MarshalIndent(payload, "", "  ")
				if encErr != nil {
					return nil, fmt.Errorf("CosmosCrawler.Crawl: marshal payload: %w", encErr)
				}
				mimeType := "application/json"
				c.cache[docURI] = &FetchResult{
					Data:         encoded,
					DetectedMime: &mimeType,
					SourcePath:   fmt.Sprintf("%s/%s/%s", c.database, cname, itemID),
				}
				total++
				cnameTotal++
			}
		}

		for _, f := range collectFieldPaths(sample) {
			c.knownFields[f] = struct{}{}
		}
		schemaText := inferSchemaText(sample, fmt.Sprintf("%s/%s", c.database, cname), cnameTotal, len(sample))
		schemaURI := fmt.Sprintf("%s://%s/%s/_schema", cosmosScheme, c.database, cname)
		plainText := "text/plain"
		c.cache[schemaURI] = &FetchResult{
			Data:         []byte(schemaText),
			DetectedMime: &plainText,
			SourcePath:   fmt.Sprintf("%s/%s/_schema", c.database, cname),
		}
	}

	log.Printf("CosmosCrawler: indexed %d item(s)", total)
	uris := make([]string, 0, len(c.cache))
	for k := range c.cache {
		uris = append(uris, k)
	}
	return uris, nil
}

