// Fetch returns the cached FetchResult for uri, or an error if not found.
func (c *CosmosCrawler) Fetch(uri string) (*FetchResult, error) {
	result, ok := c.cache[uri]
	if !ok {
		return nil, fmt.Errorf("CosmosCrawler.Fetch: unknown URI %q — call Crawl() first", uri)
	}
	return result, nil
}

// GetFieldNames returns normalized field names, container names, and database name.
// Call after Crawl(). Aliases defined in fieldAliases are applied.
func (c *CosmosCrawler) GetFieldNames() []string {
	normalized := make(map[string]struct{})
	for f := range c.knownFields {
		alias, ok := c.fieldAliases[f]
		if ok {
			normalized[alias] = struct{}{}
		} else {
			normalized[f] = struct{}{}
		}
	}
	for _, cn := range c.knownContainers {
		normalized[cn] = struct{}{}
	}
	normalized[c.database] = struct{}{}

	result := make([]string, 0, len(normalized))
	for k := range normalized {
		result = append(result, k)
	}
	sort.Strings(result)
	return result
}

