// Crawl scans the DynamoDB table, caches all items, and emits a schema chunk.
// Returns the list of dynamodb://{table}/{item_key} URIs plus one schema URI.
func (d *DynamoDBCrawler) Crawl(uri string) ([]string, error) {
	sessCfg := aws.Config{Region: aws.String(d.region)}
	var optFns []func(*dynamodb.Options)
	if d.endpoint != "" {
		optFns = append(optFns, func(o *dynamodb.Options) {
			o.BaseEndpoint = aws.String(d.endpoint)
		})
	}

	var credsProvider aws.CredentialsProvider
	if d.ak != "" {
		staticCreds := credentials.NewStaticCredentialsProvider(d.ak, d.sk, d.token)
		credsProvider = staticCreds
	}
	if credsProvider != nil {
		sessCfg.Credentials = credsProvider
	}

	ctx := context.Background()
	cfg, err := config.LoadDefaultConfig(ctx, config.WithRegion(d.region))
	if err != nil {
		return nil, fmt.Errorf("DynamoDBCrawler.Crawl: load AWS config: %w", err)
	}
	if credsProvider != nil {
		cfg.Credentials = credsProvider
	}

	client := dynamodb.NewFromConfig(cfg, optFns...)

	scanInput := &dynamodb.ScanInput{
		TableName: aws.String(d.table),
		Limit:     aws.Int32(int32(d.pageSize)),
	}
	if d.filterExpr != nil {
		scanInput.FilterExpression = d.filterExprStr
	}
	if d.projection != "" {
		scanInput.ProjectionExpression = aws.String(d.projection)
	}
	if len(d.attrNames) > 0 {
		scanInput.ExpressionAttributeNames = d.attrNames
	}

	d.cache = make(map[string]*FetchResult)
	d.knownFields = make(map[string]struct{})
	total := 0
	var sample []map[string]interface{}

	for {
		resp, scanErr := client.Scan(ctx, scanInput)
		if scanErr != nil {
			return nil, fmt.Errorf("DynamoDBCrawler.Crawl: scan: %w", scanErr)
		}

		for _, rawItem := range resp.Items {
			item := attributevalue.UnmarshalMap(rawItem)
			if len(sample) < d.schemaSampleSize {
				sample = append(sample, item)
			}
			itemKey := ""
			for _, v := range item {
				itemKey = fmt.Sprintf("%v", v)
				break
			}
			if itemKey == "" {
				itemKey = strconv.Itoa(total)
			}
			docURI := fmt.Sprintf("%s://%s/%s", dynamodbScheme, d.table, itemKey)
			payload := map[string]interface{}{
				"_source_meta": map[string]interface{}{
					"type":     "dynamodb",
					"table":    d.table,
					"region":   d.region,
					"endpoint": d.endpoint,
				},
			}
			for k, v := range item {
				payload[k] = v
			}
			encoded, encErr := json.MarshalIndent(payload, "", "  ")
			if encErr != nil {
				return nil, fmt.Errorf("DynamoDBCrawler.Crawl: marshal payload: %w", encErr)
			}
			mimeType := "application/json"
			d.cache[docURI] = &FetchResult{
				Data:         encoded,
				DetectedMime: &mimeType,
				SourcePath:   fmt.Sprintf("%s/%s", d.table, itemKey),
			}
			total++
		}

		if resp.LastEvaluatedKey == nil || len(resp.LastEvaluatedKey) == 0 {
			break
		}
		scanInput.ExclusiveStartKey = resp.LastEvaluatedKey
	}

	for _, f := range collectFieldPaths(sample) {
		d.knownFields[f] = struct{}{}
	}
	schemaText := inferSchemaText(sample, d.table, total, len(sample))
	schemaURI := fmt.Sprintf("%s://%s/_schema", dynamodbScheme, d.table)
	plainText := "text/plain"
	d.cache[schemaURI] = &FetchResult{
		Data:         []byte(schemaText),
		DetectedMime: &plainText,
		SourcePath:   fmt.Sprintf("%s/_schema", d.table),
	}

	log.Printf("DynamoDBCrawler: indexed %d item(s) from %q", total, d.table)
	uris := make([]string, 0, len(d.cache))
	for k := range d.cache {
		uris = append(uris, k)
	}
	return uris, nil
}

