// GetFieldNames returns normalized attribute names and table name.
// Call after Crawl(). Aliases defined in fieldAliases are applied.
func (d *DynamoDBCrawler) GetFieldNames() []string {
	normalized := make(map[string]struct{})
	for f := range d.knownFields {
		alias, ok := d.fieldAliases[f]
		if ok {
			normalized[alias] = struct{}{}
		} else {
			normalized[f] = struct{}{}
		}
	}
	normalized[d.table] = struct{}{}

	result := make([]string, 0, len(normalized))
	for k := range normalized {
		result = append(result, k)
	}
	sort.Strings(result)
	return result
}

