const userAgent = "chonk/0.1"

var (
	httpClientOnce sync.Once
	sharedHTTPClient *http.Client
)

func getHTTPClient() *http.Client {
	httpClientOnce.Do(func() {
		sharedHTTPClient = &http.Client{
			Transport: &userAgentTransport{
				userAgent: userAgent,
				base:      http.DefaultTransport,
			},
		}
	})
	return sharedHTTPClient
}

type userAgentTransport struct {
	userAgent string
	base      http.RoundTripper
}

func (t *userAgentTransport) RoundTrip(req *http.Request) (*http.Response, error) {
	req = req.Clone(req.Context())
	req.Header.Set("User-Agent", t.userAgent)
	return t.base.RoundTrip(req)
}

// HttpTransport fetches documents via HTTP or HTTPS.
type HttpTransport struct{}

// CanHandle reports whether this transport handles http:// or https:// URIs.
func (t *HttpTransport) CanHandle(uri string) bool {
	return strings.HasPrefix(uri, "http://") || strings.HasPrefix(uri, "https://")
}

// HttpFetchOptions carries optional parameters for Fetch.
type HttpFetchOptions struct {
	Headers map[string]string
	Timeout time.Duration // 0 means use default (30 seconds)
}

// Fetch retrieves the document at uri via HTTP GET.
func (t *HttpTransport) Fetch(uri string, opts HttpFetchOptions) (*FetchResult, error) {
	client := getHTTPClient()

	timeout := opts.Timeout
	if timeout == 0 {
		timeout = 30 * time.Second
	}

	req, err := http.NewRequestWithContext(context.Background(), http.MethodGet, uri, nil)
	if err != nil {
		return nil, fmt.Errorf("HttpTransport.Fetch: create request: %w", err)
	}
	for k, v := range opts.Headers {
		req.Header.Set(k, v)
	}

	clientWithTimeout := *client
	clientWithTimeout.Timeout = timeout

	resp, err := clientWithTimeout.Do(req)
	if err != nil {
		return nil, fmt.Errorf("HttpTransport.Fetch: GET %s: %w", uri, err)
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return nil, fmt.Errorf("HttpTransport.Fetch: GET %s: status %d", uri, resp.StatusCode)
	}

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("HttpTransport.Fetch: read body: %w", err)
	}

	var detectedMime *string
	if ct := resp.Header.Get("Content-Type"); ct != "" {
		detectedMime = &ct
	}
	return &FetchResult{
		Data:         data,
		DetectedMime: detectedMime,
		SourcePath:   uri,
	}, nil
}
